import { useEffect } from "react";
import { useLocation } from "wouter";
import { calculatorRoutes } from "@/data/siteRoutes";

type SmartField = {
  value: string;
  checked?: boolean;
  count: number;
  updatedAt: number;
};

type SmartDefaultsStore = {
  version: number;
  fields: Record<string, SmartField>;
  globalFields: Record<string, SmartField>;
};

const STORAGE_KEY = "calchive-smart-defaults:v1";
const calculatorPathSet = new Set(calculatorRoutes.map((route) => route.path));

function isCalculatorPath(pathname: string) {
  return calculatorPathSet.has(pathname);
}

function readStore(): SmartDefaultsStore {
  try {
    const parsed = JSON.parse(localStorage.getItem(STORAGE_KEY) || "");
    if (parsed?.version === 1 && parsed.fields && parsed.globalFields) return parsed;
  } catch {
    // Keep smart defaults invisible if localStorage is unavailable or malformed.
  }
  return { version: 1, fields: {}, globalFields: {} };
}

function writeStore(store: SmartDefaultsStore) {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(store));
  } catch {
    // Ignore storage quota/private mode failures.
  }
}

function isVisible(element: Element) {
  const el = element as HTMLElement;
  return Boolean(el.offsetParent || el.getClientRects().length);
}

function labelForField(field: HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement) {
  const id = field.id ? CSS.escape(field.id) : "";
  const label =
    (id ? document.querySelector(`label[for="${id}"]`)?.textContent : "") ||
    (id ? document.querySelector(`label[for="${id}-slider"]`)?.textContent : "") ||
    field.closest("label")?.textContent ||
    field.getAttribute("aria-label") ||
    field.getAttribute("placeholder") ||
    field.name ||
    field.id ||
    "";

  return label.replace(/\s+/g, " ").trim().replace(/\s*\*$/, "");
}

function normalizedLabel(field: HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement) {
  return labelForField(field)
    .toLowerCase()
    .replace(/\([^)]*\)/g, "")
    .replace(/[^a-z0-9]+/g, " ")
    .trim();
}

function canUseField(field: HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement) {
  if (!isVisible(field)) return false;
  if (field.disabled) return false;
  if ((field instanceof HTMLInputElement || field instanceof HTMLTextAreaElement) && field.readOnly) return false;
  if (field.closest("nav, header, footer, [data-chatbot], [data-newsletter], [data-calculation-history-root]")) return false;
  if (field instanceof HTMLInputElement) {
    if (["hidden", "button", "submit", "reset", "file", "password", "search", "range"].includes(field.type)) return false;
  }
  return Boolean(normalizedLabel(field));
}

function shouldRememberField(field: HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement) {
  const label = normalizedLabel(field);
  if (field instanceof HTMLSelectElement) return true;
  if (field instanceof HTMLTextAreaElement) return false;
  if (field.type === "checkbox" || field.type === "radio") return true;
  if (["number", "text", "tel", "date", "datetime-local", "month", "email"].includes(field.type)) {
    return /unit|metric|imperial|income|salary|wage|age|height|weight|gender|rate|term|amount|price|balance|payment|tax|state|country|currency|goal|activity|deposit|contribution|rent|cost|year|month|week|day/i.test(label);
  }
  return false;
}

function fieldKey(pathname: string, field: HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement) {
  const id = field.name || field.id || normalizedLabel(field);
  return `${pathname}:${id}:${normalizedLabel(field)}`;
}

function globalFieldKey(field: HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement) {
  const label = normalizedLabel(field);
  if (/metric|imperial|unit/.test(label)) return "preferred-units";
  if (/currency/.test(label)) return "preferred-currency";
  if (/state/.test(label)) return "preferred-state";
  if (/country/.test(label)) return "preferred-country";
  if (/gender/.test(label)) return "preferred-gender";
  if (/activity/.test(label)) return "preferred-activity";
  if (/income|salary|wage/.test(label)) return "preferred-income";
  if (/height/.test(label)) return "preferred-height";
  if (/weight/.test(label)) return "preferred-weight";
  if (/age/.test(label)) return "preferred-age";
  return "";
}

function setNativeValue(field: HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement, saved: SmartField) {
  if (field instanceof HTMLInputElement && (field.type === "checkbox" || field.type === "radio")) {
    const descriptor = Object.getOwnPropertyDescriptor(HTMLInputElement.prototype, "checked");
    descriptor?.set?.call(field, Boolean(saved.checked));
  } else {
    const prototype =
      field instanceof HTMLTextAreaElement ? HTMLTextAreaElement.prototype :
      field instanceof HTMLSelectElement ? HTMLSelectElement.prototype :
      HTMLInputElement.prototype;
    const descriptor = Object.getOwnPropertyDescriptor(prototype, "value");
    descriptor?.set?.call(field, saved.value);
  }

  field.dataset.smartDefaultApplied = "true";
  field.dispatchEvent(new Event("input", { bubbles: true }));
  field.dispatchEvent(new Event("change", { bubbles: true }));
}

function valuesMatch(current: SmartField | undefined, nextValue: string, nextChecked?: boolean) {
  if (!current) return false;
  return current.value === nextValue && current.checked === nextChecked;
}

function rememberField(pathname: string, field: HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement) {
  if (!canUseField(field) || !shouldRememberField(field)) return;

  const value = field.value.trim();
  const checked = field instanceof HTMLInputElement && (field.type === "checkbox" || field.type === "radio") ? field.checked : undefined;
  if (!value && checked === undefined) return;

  const store = readStore();
  const now = Date.now();
  const key = fieldKey(pathname, field);
  const globalKey = globalFieldKey(field);
  const current = store.fields[key];
  const nextCount = valuesMatch(current, value, checked) ? current.count + 1 : 1;

  store.fields[key] = { value, checked, count: nextCount, updatedAt: now };

  if (globalKey) {
    const globalCurrent = store.globalFields[globalKey];
    store.globalFields[globalKey] = {
      value,
      checked,
      count: valuesMatch(globalCurrent, value, checked) ? globalCurrent.count + 1 : 1,
      updatedAt: now,
    };
  }

  writeStore(store);
}

function applyDefaults(pathname: string) {
  if (new URLSearchParams(window.location.search).has("calc")) return;

  const store = readStore();
  const fields = Array.from(document.querySelectorAll("main input, main select, main textarea"))
    .filter((field): field is HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement =>
      field instanceof HTMLInputElement || field instanceof HTMLSelectElement || field instanceof HTMLTextAreaElement,
    )
    .filter((field) => canUseField(field) && shouldRememberField(field));

  fields.forEach((field) => {
    if (field.dataset.smartDefaultApplied === "true") return;

    const exact = store.fields[fieldKey(pathname, field)];
    const globalKey = globalFieldKey(field);
    const global = globalKey ? store.globalFields[globalKey] : undefined;
    const saved = exact || (global && global.count >= 2 ? global : undefined);
    if (!saved?.value) return;

    const optionExists =
      !(field instanceof HTMLSelectElement) ||
      Array.from(field.options).some((option) => option.value === saved.value);
    if (!optionExists) return;

    setNativeValue(field, saved);
  });
}

export default function SmartDefaults() {
  const [location] = useLocation();

  useEffect(() => {
    if (typeof window === "undefined" || !isCalculatorPath(location)) return;

    const applyTimer = window.setTimeout(() => applyDefaults(location), 550);
    let saveTimer: number | undefined;

    const onInput = (event: Event) => {
      const target = event.target;
      if (!(target instanceof HTMLInputElement || target instanceof HTMLSelectElement || target instanceof HTMLTextAreaElement)) return;
      window.clearTimeout(saveTimer);
      saveTimer = window.setTimeout(() => rememberField(location, target), 300);
    };

    document.addEventListener("input", onInput);
    document.addEventListener("change", onInput);

    return () => {
      window.clearTimeout(applyTimer);
      window.clearTimeout(saveTimer);
      document.removeEventListener("input", onInput);
      document.removeEventListener("change", onInput);
    };
  }, [location]);

  return null;
}
